
-- 1）先构建一个用户样本；sql中以【每天发起用信申请的用户 + 用信申请时间】作为计算特征的目标人群；真实场景中以【调用特征用户当时的实际业务时间为准】
-- target_user只是服务于实时特征上线前，和后端结果回溯上线使用；
with target_user as (
    select id as apply_id, create_time as use_create_time,cust_no
    from hive_idc.oversea.ods_mx_aprv_approve_use_credit_apply_df
    where pt ='${dt}' -- yyymmdd格式
    and replace(substr(create_time,1,10) ,'-', '')  ='${dt}'
)
-- PART 1 : 第一部分特征
-- 2）调用实时特征时，对应用户历史订单行为（基于还款计划）；
-- and t2.update_time < t1.create_time   --窗口之前该用户的还款计划数据
-- and (t2.settled_time is null or t2.settled_time < t1.create_time)   --窗口之前该用户的还款计划数据
-- 在贷款订单逻辑：(t4.settled_time is null or t4.settled_time>t3.use_create_time) 未还或窗口期后还的
-- 在贷续借订单逻辑：(t4.settled_time is null or t4.settled_time>t3.use_create_time) and t3.order_asc_rank>1 除了第一笔订单,未还或窗口期后还的
-- 逾期账单的逻辑：t3.loan_end_date < substr(t3.use_create_time,1,10) and (t3.settled_time is null or substr(t3.settled_time,1,10)> t3.loan_end_date) 已过期未还 or 过期后还的
-- 到期账单逻辑：t3.loan_end_date <= substr(t3.use_create_time,1,10) 已过期所有
-- 提前结清：t3.settled_time < t3.use_create_time and substr(t3.settled_time,1,10) < t3.loan_end_date 已提前还

select * from (
select t3.apply_id
     ,t3.cust_no
     ,t3.use_create_time
    -- 最远一笔订单相关
     ,coalesce(count(if(t3.order_asc_rank=1 and t3.settled_time is not null and t3.settled_time < t3.use_create_time ,t3.id ,null)), -999) as multi_loan_order_info_furthestsingleorder_completetermcnt
     ,coalesce(round(count(if(t3.order_asc_rank=1 and t3.settled_time is not null and t3.settled_time < t3.use_create_time ,t3.id ,null))/count(if(t3.order_asc_rank=1, t3.id, null)), 6), -999) as multi_loan_order_info_furthestsingleorder_completetermratio
     ,coalesce(count(if(t3.order_asc_rank=1 and t3.settled_time is not null and t3.settled_time < t3.use_create_time and substr(t3.settled_time,1,10) < t3.loan_end_date, t3.id ,null)), -999) as multi_loan_order_info_furthestsingleorder_completefutureduetermcnt
     ,coalesce(round(count(if(t3.order_asc_rank=1 and t3.settled_time is not null and t3.settled_time < t3.use_create_time and substr(t3.settled_time,1,10) < t3.loan_end_date, t3.id ,null))/count(if(t3.order_asc_rank=1 and t3.settled_time is not null and t3.settled_time < t3.use_create_time ,t3.id ,null)), 6), -999) as multi_loan_order_info_furthestsingleorder_completefutureduetermratio
     ,coalesce(round(count(if(t3.order_asc_rank=1 and t3.settled_time is not null and t3.settled_time < t3.use_create_time and substr(t3.settled_time,1,10) < t3.loan_end_date, t3.id ,null))/count(if(t3.order_asc_rank=1 and t3.loan_end_date >substr(t3.use_create_time,1,10) ,t3.id ,null)), 6), -999) as multi_loan_order_info_furthestsingleorder_prepayvsfuturebillingtermratio
     ,coalesce(max(if(t3.order_asc_rank=1, t3.periods, null)), -999) as multi_loan_order_info_furthestsingleorder_termscnt
     ,coalesce((datediff(max(if(t3.order_asc_rank=1, t3.loan_end_date, null)),min(if(t3.order_asc_rank=1, t3.loan_start_date, null))) + 1), -999) as multi_loan_order_info_furthestsingleorder_payoutdays
     ,coalesce(count(if(t3.order_asc_rank=1 and (t3.settled_time is null or t3.settled_time > t3.use_create_time) ,t3.id ,null)), -999) as multi_loan_order_info_furthestsingleorder_incompletetermcnt
     ,coalesce(round(count(if(t3.order_asc_rank=1 and t3.settled_time is not null and t3.settled_time < t3.use_create_time and substr(t3.settled_time,1,10) < t3.loan_end_date,t3.id ,null))/max(if(t3.order_asc_rank=1,t3.periods, null)), 6), -999) as multi_loan_order_info_furthestsingleorder_prepayvsalltermratio
     ,coalesce(round(count(if(t3.order_asc_rank=1 and t3.settled_time is not null and t3.settled_time < t3.use_create_time and substr(t3.settled_time,1,10)> t3.loan_end_date,t3.id ,null))/count(if(t3.order_asc_rank=1 and t3.settled_time is not null and t3.settled_time < t3.use_create_time ,t3.id ,null)), 6), -999) as multi_loan_order_info_furthestsingleorder_overduevscompletedtermratio
     ,coalesce(round(count(if(t3.order_asc_rank=1 and t3.loan_end_date < substr(t3.use_create_time,1,10) and (t3.settled_time is null or substr(t3.settled_time,1,10)> t3.loan_end_date),t3.id,null))/count(if(t3.order_asc_rank=1 and t3.loan_end_date <= substr(t3.use_create_time,1,10),t3.id,null)), 6), -999) as multi_loan_order_info_furthestsingleorder_overduevsbillingtermratio
     ,coalesce(round(count(if(t3.order_asc_rank=1 and t3.loan_end_date < substr(t3.use_create_time,1,10) and (t3.settled_time is null or substr(t3.settled_time,1,10)> t3.loan_end_date),t3.id,null))/max(if(t3.order_asc_rank=1,t3.periods, null)), 6), -999) as multi_loan_order_info_furthestsingleorder_overduetermratio
     ,coalesce(count(if(t3.order_asc_rank=1 and t3.loan_end_date < substr(t3.use_create_time,1,10) and (t3.settled_time is null or substr(t3.settled_time,1,10)> t3.loan_end_date),t3.id,null)), -999) as multi_loan_order_info_furthestsingleorder_overduetermcnt
     ,coalesce(datediff(min(if(t3.order_asc_rank=1 and t3.settled_time is not null and t3.settled_time < t3.use_create_time, cast(t3.settled_time as date), null)),min(if(t3.order_asc_rank=1,cast(t3.create_time as date), null))), -999) as multi_loan_order_info_furthestsingleorder_firstcompletedcreatedgap
     ,coalesce(datediff(cast(t3.use_create_time as date), min(if(t3.order_asc_rank=1,cast(t6.create_time as date), null))), -999) as multi_loan_order_info_furthestsingleorder_creatednowgap
     ,coalesce(max(if(t3.order_asc_rank=1 and substr(t6.create_time, 12, 2) in('11','12','13'), 1, 0)), -999) as multi_loan_order_info_furthestsingleorder_creatednoon
     ,coalesce(max(if(t3.order_asc_rank=1 and substr(t6.create_time, 12, 2) in('23','00','01','02','03','04'), 1, 0)), -999) as multi_loan_order_info_furthestsingleorder_creatednight
     ,coalesce(max(if(t3.order_asc_rank=1 and substr(t6.create_time, 12, 2) in('05','06','07','08','09','10'), 1, 0)), -999) as multi_loan_order_info_furthestsingleorder_createdmorning
     ,coalesce(max(if(t3.order_asc_rank=1 and substr(t6.create_time, 12, 2) in('18','19','20','21','22'), 1, 0)), -999) as multi_loan_order_info_furthestsingleorder_createdevening
     ,coalesce(max(if(t3.order_asc_rank=1 and substr(t6.create_time, 12, 2) in('14','15','16','17'), 1, 0)), -999) as multi_loan_order_info_furthestsingleorder_createdafternoon
     ,coalesce(round(count(if(t3.order_asc_rank=1 and t3.settled_time is not null and t3.settled_time < t3.use_create_time ,t3.id ,null))/count(if(t3.order_asc_rank=1 and t3.loan_end_date > substr(t3.use_create_time,1,10) ,t3.id ,null)), 6), -999) as multi_loan_order_info_furthestsingleorder_completevsfuturebillingtermratio
     ,coalesce(min(if(t3.order_asc_rank=1 and t3.settled_time is not null and t3.settled_time < t3.use_create_time and substr(t3.settled_time,1,10) < t3.loan_end_date, datediff(cast(t3.loan_end_date as date), cast(substr(t3.settled_time,1,10) as date)),null)), -999) as multi_loan_order_info_furthestsingleorder_completeprepaydaysmin
     ,coalesce(round(avg(if(t3.order_asc_rank=1 and t3.settled_time is not null and t3.settled_time < t3.use_create_time and substr(t3.settled_time,1,10) < t3.loan_end_date, datediff(cast(t3.loan_end_date as date), cast(substr(t3.settled_time,1,10) as date)),null)), 6), -999) as multi_loan_order_info_furthestsingleorder_completeprepaydaysmean
     ,coalesce(max(if(t3.order_asc_rank=1 and t3.settled_time is not null and t3.settled_time < t3.use_create_time and substr(t3.settled_time,1,10) < t3.loan_end_date, datediff(cast(t3.loan_end_date as date), cast(substr(t3.settled_time,1,10) as date)),null)), -999) as multi_loan_order_info_furthestsingleorder_completeprepaydaysmax
     ,coalesce(round(sum(if(t3.order_asc_rank=1 and t3.settled_time is not null and t3.settled_time < t3.use_create_time and dayofweek(str_to_date(substr(t3.settled_time,1,10), '%Y-%m-%d')) IN (1, 7), t3.repaid_principal+t3.repaid_interest+t3.repaid_service_fee+t3.repaid_penalty,0))/sum(if(t3.order_asc_rank=1 and t3.settled_time is not null and t3.settled_time < t3.use_create_time , t3.repaid_principal+t3.repaid_interest+t3.repaid_service_fee+t3.repaid_penalty,0)), 6), -999) as multi_loan_order_info_furthestsingleorder_completeonweekendprincipalratio
     ,coalesce(round(count(if(t3.order_asc_rank=1 and t3.settled_time is not null and t3.settled_time < t3.use_create_time and substr(t3.settled_time,1,10) < t3.loan_end_date,t3.id ,null))/count(if(t3.order_asc_rank=1 and t3.settled_time is not null and t3.settled_time < t3.use_create_time and substr(t3.settled_time,1,10)<=t3.last_loan_end_date ,t3.id ,null)), 6), -999) as multi_loan_order_info_furthestsingleorder_billingprepayvscompletetermratio
     ,coalesce(round(count(if(t3.order_asc_rank=1 and t3.settled_time is not null and t3.settled_time < t3.use_create_time and substr(t3.settled_time,1,10) < t3.loan_end_date,t3.id ,null))/count(if(t3.order_asc_rank=1 and t3.loan_end_date <= substr(t3.use_create_time,1,10),t3.id,null)), 6), -999) as multi_loan_order_info_furthestsingleorder_billingprepayvsbillingtermratio
    -- 最近第一笔订单相关
      ,coalesce(max(if(t3.order_desc_rank=1 and substr(t6.create_time, 12, 2) in('11','12','13'), 1, 0)), -999) as multi_loan_order_info_latest1singleorder_creatednoon
     ,coalesce(max(if(t3.order_desc_rank=1 and substr(t6.create_time, 12, 2) in('23','00','01','02','03','04'), 1, 0)), -999) as multi_loan_order_info_latest1singleorder_creatednight
     ,coalesce(max(if(t3.order_desc_rank=1 and substr(t6.create_time, 12, 2) in('05','06','07','08','09','10'), 1, 0)), -999) as multi_loan_order_info_latest1singleorder_createdmorning
     ,coalesce(max(if(t3.order_desc_rank=1 and substr(t6.create_time, 12, 2) in('18','19','20','21','22'), 1, 0)), -999) as multi_loan_order_info_latest1singleorder_createdevening
     ,coalesce(max(if(t3.order_desc_rank=1 and substr(t6.create_time, 12, 2) in('14','15','16','17'), 1, 0)), -999) as multi_loan_order_info_latest1singleorder_createdafternoon
     ,coalesce(max(if(t3.order_desc_rank=1,datediff(cast(t6.create_time as date),cast(t7.create_time as date)),null)), -999) as multi_loan_order_info_latest1singleorder_createdcalccreditgap
     ,coalesce(round(count(if(t3.order_desc_rank=1 and t3.settled_time is not null and t3.settled_time<t3.use_create_time and t3.loan_end_date >substr(t3.use_create_time,1,10),t3.id,null))/count(if(t3.order_desc_rank=1 and t3.loan_end_date >substr(t3.use_create_time,1,10),t3.id,null)), 6), -999) as multi_loan_order_info_latest1singleorder_completevsfuturebillingtermratio
     ,coalesce(round(count(if(t3.order_desc_rank=1 and t3.settled_time is not null and t3.settled_time<t3.use_create_time, t3.id, null))/max(if(t3.order_desc_rank=1,t3.periods, null)), 6), -999) as multi_loan_order_info_latest1singleorder_completetermratio
     ,coalesce(count(if(t3.order_desc_rank=1 and t3.settled_time is not null and t3.settled_time<t3.use_create_time, t3.id, null)), -999) as multi_loan_order_info_latest1singleorder_completetermcnt
     ,coalesce(min(if(t3.order_desc_rank=1 and t3.settled_time is not null and t3.settled_time < t3.use_create_time and substr(t3.settled_time,1,10) < t3.loan_end_date, datediff(cast(t3.loan_end_date as date), cast(substr(t3.settled_time,1,10) as date)),null)), -999) as multi_loan_order_info_latest1singleorder_completeprepaydaysmin
     ,coalesce(round(avg(if(t3.order_desc_rank=1 and t3.settled_time is not null and t3.settled_time < t3.use_create_time and substr(t3.settled_time,1,10) < t3.loan_end_date, datediff(cast(t3.loan_end_date as date), cast(substr(t3.settled_time,1,10) as date)),null)), 6), -999) as multi_loan_order_info_latest1singleorder_completeprepaydaysmean
     ,coalesce(max(if(t3.order_desc_rank=1 and t3.settled_time is not null and t3.settled_time < t3.use_create_time and substr(t3.settled_time,1,10) < t3.loan_end_date, datediff(cast(t3.loan_end_date as date), cast(substr(t3.settled_time,1,10) as date)),null)), -999) as multi_loan_order_info_latest1singleorder_completeprepaydaysmax
     ,coalesce(round(count(if(t3.order_desc_rank=1 and t3.settled_time is not null and t3.settled_time < t3.use_create_time and substr(t3.settled_time,1,10) < t3.loan_end_date, t3.id ,null))/count(if(t3.order_desc_rank=1 and t3.settled_time is not null and t3.settled_time < t3.use_create_time ,t3.id ,null)), 6), -999) as multi_loan_order_info_latest1singleorder_completefutureduetermratio
     ,coalesce(count(if(t3.order_desc_rank=1 and t3.settled_time is not null and t3.settled_time < t3.use_create_time and substr(t3.settled_time,1,10) < t3.loan_end_date, t3.id ,null)), -999) as multi_loan_order_info_latest1singleorder_completefutureduetermcnt
     ,coalesce(round(count(if(t3.order_desc_rank=1 and t3.settled_time is not null and t3.settled_time < t3.use_create_time and substr(t3.settled_time,1,10) < t3.loan_end_date,t3.id ,null))/count(if(t3.order_desc_rank=1 and t3.settled_time is not null and t3.settled_time < t3.use_create_time and substr(t3.settled_time,1,10)<=t3.last_loan_end_date ,t3.id ,null)), 6), -999) as multi_loan_order_info_latest1singleorder_billingprepayvscompletetermratio
     ,coalesce(round(count(if(t3.order_desc_rank=1 and t3.settled_time is not null and t3.settled_time < t3.use_create_time and substr(t3.settled_time,1,10) < t3.loan_end_date,t3.id ,null))/count(if(t3.order_desc_rank=1 and t3.loan_end_date <= substr(t3.use_create_time,1,10),t3.id,null)), 6), -999) as multi_loan_order_info_latest1singleorder_billingprepayvsbillingtermratio
     ,coalesce(datediff(cast(t3.use_create_time as date), min(if(t3.order_desc_rank=1,cast(t6.create_time as date), null))), -999) as multi_loan_order_info_latest1singleorder_creatednowgap
     ,coalesce(datediff(min(if(t3.order_desc_rank=1 and t3.settled_time is not null and t3.settled_time < t3.use_create_time, cast(t3.settled_time as date), null)),min(if(t3.order_desc_rank=1,cast(t3.create_time as date), null))), -999) as multi_loan_order_info_latest1singleorder_firstcompletedcreatedgap
     ,coalesce(count(if(t3.order_desc_rank=1 and (t3.settled_time is null or t3.settled_time > t3.use_create_time) ,t3.id ,null)), -999) as multi_loan_order_info_latest1singleorder_incompletetermcnt
     ,coalesce(count(if(t3.order_desc_rank=1 and t3.loan_end_date < substr(t3.use_create_time,1,10) and (t3.settled_time is null or substr(t3.settled_time,1,10)> t3.loan_end_date),t3.id,null)), -999) as multi_loan_order_info_latest1singleorder_overduetermcnt
     ,coalesce(round(count(if(t3.order_desc_rank=1 and t3.loan_end_date < substr(t3.use_create_time,1,10) and (t3.settled_time is null or substr(t3.settled_time,1,10)> t3.loan_end_date),t3.id,null))/max(if(t3.order_desc_rank=1,t3.periods, null)), 6), -999) as multi_loan_order_info_latest1singleorder_overduetermratio
     ,coalesce(round(count(if(t3.order_desc_rank=1 and t3.loan_end_date < substr(t3.use_create_time,1,10) and (t3.settled_time is null or substr(t3.settled_time,1,10)> t3.loan_end_date),t3.id,null))/count(if(t3.order_desc_rank=1 and t3.loan_end_date <= substr(t3.use_create_time,1,10),t3.id,null)), 6), -999) as multi_loan_order_info_latest1singleorder_overduevsbillingtermratio
     ,coalesce(round(count(if(t3.order_desc_rank=1 and t3.settled_time is not null and t3.settled_time < t3.use_create_time and substr(t3.settled_time,1,10)> t3.loan_end_date,t3.id ,null))/count(if(t3.order_desc_rank=1 and t3.settled_time is not null and t3.settled_time < t3.use_create_time ,t3.id ,null)), 6), -999) as multi_loan_order_info_latest1singleorder_overduevscompletedtermratio
     ,coalesce((datediff(max(if(t3.order_desc_rank=1, t3.loan_end_date, null)),min(if(t3.order_desc_rank=1, t3.loan_start_date, null))) + 1), -999) as multi_loan_order_info_latest1singleorder_payoutdays
     ,coalesce(round(count(if(t3.order_desc_rank=1 and t3.settled_time is not null and t3.settled_time < t3.use_create_time and substr(t3.settled_time,1,10) < t3.loan_end_date,t3.id ,null))/max(if(t3.order_desc_rank=1,t3.periods, null)), 6), -999) as multi_loan_order_info_latest1singleorder_prepayvsalltermratio
     ,coalesce(round(count(if(t3.order_desc_rank=1 and t3.settled_time is not null and t3.settled_time < t3.use_create_time and substr(t3.settled_time,1,10) < t3.loan_end_date, t3.id ,null))/count(if(t3.order_desc_rank=1 and t3.loan_end_date >substr(t3.use_create_time,1,10) ,t3.id ,null)), 6), -999) as multi_loan_order_info_latest1singleorder_prepayvsfuturebillingtermratio
     ,coalesce(max(if(t3.order_desc_rank=1, t3.periods, null)), -999) as multi_loan_order_info_latest1singleorder_termscnt
     -- 最近第二笔订单相关
     ,coalesce(max(if(t3.order_desc_rank=2 and substr(t6.create_time, 12, 2) in('11','12','13'), 1, 0)), -999) as multi_loan_order_info_latest2singleorder_creatednoon
     ,coalesce(max(if(t3.order_desc_rank=2 and substr(t6.create_time, 12, 2) in('23','00','01','02','03','04'), 1, 0)), -999) as multi_loan_order_info_latest2singleorder_creatednight
     ,coalesce(max(if(t3.order_desc_rank=2 and substr(t6.create_time, 12, 2) in('05','06','07','08','09','10'), 1, 0)), -999) as multi_loan_order_info_latest2singleorder_createdmorning
     ,coalesce(max(if(t3.order_desc_rank=2 and substr(t6.create_time, 12, 2) in('18','19','20','21','22'), 1, 0)), -999) as multi_loan_order_info_latest2singleorder_createdevening
     ,coalesce(max(if(t3.order_desc_rank=2 and substr(t6.create_time, 12, 2) in('14','15','16','17'), 1, 0)), -999) as multi_loan_order_info_latest2singleorder_createdafternoon
     ,coalesce(max(if(t3.order_desc_rank=2,datediff(cast(t6.create_time as date),cast(t7.create_time as date)),null)), -999) as multi_loan_order_info_latest2singleorder_createdcalccreditgap
     ,coalesce(round(count(if(t3.order_desc_rank=2 and t3.settled_time is not null and t3.settled_time<t3.use_create_time and t3.loan_end_date >substr(t3.use_create_time,1,10),t3.id,null))/count(if(t3.order_desc_rank=2 and t3.loan_end_date >substr(t3.use_create_time,1,10),t3.id,null)), 6), -999) as multi_loan_order_info_latest2singleorder_completevsfuturebillingtermratio
     ,coalesce(round(count(if(t3.order_desc_rank=2 and t3.settled_time is not null and t3.settled_time<t3.use_create_time, t3.id, null))/max(if(t3.order_desc_rank=2,t3.periods, null)), 6), -999) as multi_loan_order_info_latest2singleorder_completetermratio
     ,coalesce(count(if(t3.order_desc_rank=2 and t3.settled_time is not null and t3.settled_time<t3.use_create_time, t3.id, null)), -999) as multi_loan_order_info_latest2singleorder_completetermcnt
