     ,coalesce(round(count(if((t4.settled_time is null or t4.settled_time>t3.use_create_time) and t3.order_asc_rank>1 and t3.settled_time < t3.use_create_time and substr(t3.settled_time,1,10) < date_add(t3.loan_end_date,-3),t3.id,null))/count(if((t4.settled_time is null or t4.settled_time>t3.use_create_time) and t3.order_asc_rank>1 and t3.settled_time < t3.use_create_time and substr(t3.settled_time,1,10) < t3.loan_end_date,t3.id,null)), 6), -999) as multi_loan_in_loan_order_all_advanceget3days_completedadvanceinstaloverallcompletedadvanceratio
     ,coalesce(round(count(if((t4.settled_time is null or t4.settled_time>t3.use_create_time) and t3.order_asc_rank>1 and t3.settled_time < t3.use_create_time and substr(t3.settled_time,1,10) < date_add(t3.loan_end_date,-3),t3.id,null))/count(if((t4.settled_time is null or t4.settled_time>t3.use_create_time) and t3.order_asc_rank>1 and (t3.settled_time < t3.use_create_time or t3.loan_end_date <= substr(t3.use_create_time,1,10)),t3.id,null)), 6), -999) as multi_loan_in_loan_order_all_advanceget3days_completedadvanceinstaloverdueorcompletedratio
     ,coalesce(count(if((t4.settled_time is null or t4.settled_time>t3.use_create_time) and t3.order_asc_rank>1 and t3.settled_time < t3.use_create_time and substr(t3.settled_time,1,10) < t3.loan_end_date, t3.id,null)), -999) as multi_loan_in_loan_order_all_completedadvanceinstalcnt
     ,coalesce(round(count(if((t4.settled_time is null or t4.settled_time>t3.use_create_time) and t3.order_asc_rank>1 and t3.settled_time < t3.use_create_time and substr(t3.settled_time,1,10) < t3.loan_end_date,t3.id,null))/count(if((t4.settled_time is null or t4.settled_time>t3.use_create_time) and t3.order_asc_rank>1 and (t3.settled_time < t3.use_create_time or t3.loan_end_date <= substr(t3.use_create_time,1,10)),t3.id,null)), 6), -999) as multi_loan_in_loan_order_all_completedadvanceinstalratio
     ,coalesce(round(sum(if((t4.settled_time is null or t4.settled_time>t3.use_create_time) and t3.order_asc_rank>1 and t3.settled_time < t3.use_create_time and substr(t3.settled_time,1,10) >= date_add(t3.loan_end_date,-30) and substr(t3.settled_time,1,10) < date_add(t3.loan_end_date,0) ,t3.repaid_principal,0))/sum(if((t4.settled_time is null or t4.settled_time>t3.use_create_time) and t3.order_asc_rank>1 and t3.settled_time < t3.use_create_time,t3.repaid_principal,0)), 6), -999) as multi_loan_in_loan_order_all_completedadvanceloanamountovercompletedratioforfirstmonth
     ,coalesce(count(if((t4.settled_time is null or t4.settled_time>t3.use_create_time) and t3.order_asc_rank>1 and t3.settled_time < t3.use_create_time,t3.id,null)), -999) as multi_loan_in_loan_order_all_completedinstalcnt
     ,coalesce(round(count(if((t4.settled_time is null or t4.settled_time>t3.use_create_time) and t3.order_asc_rank>1 and t3.settled_time < t3.use_create_time,t3.id,null))/count(if((t4.settled_time is null or t4.settled_time>t3.use_create_time) and t3.order_asc_rank>1,t3.id,null)), 6), -999) as multi_loan_in_loan_order_all_completedinstalratio
     ,coalesce(sum(if((t4.settled_time is null or t4.settled_time>t3.use_create_time) and t3.order_asc_rank>1 and t3.settled_time < t3.use_create_time,t3.repaid_principal,0)), -999) as multi_loan_in_loan_order_all_completedloanamount
     ,coalesce(round(avg(if((t4.settled_time is null or t4.settled_time>t3.use_create_time) and t3.order_asc_rank>1 and t3.periods=1,datediff(cast(t3.use_create_time as date), cast(t6.create_time as date)),null)), 6), -999) as multi_loan_in_loan_order_all_createdorderdaysgapmathcount_avg
     ,coalesce(max(if((t4.settled_time is null or t4.settled_time>t3.use_create_time) and t3.order_asc_rank>1 and t3.periods=1,datediff(cast(t3.use_create_time as date), cast(t6.create_time as date)),null)), -999) as multi_loan_in_loan_order_all_createdorderdaysgapmathcount_max
     ,coalesce(round(stddev(if((t4.settled_time is null or t4.settled_time>t3.use_create_time) and t3.order_asc_rank>1 and t3.periods=1,datediff(cast(t3.use_create_time as date), cast(t6.create_time as date)),null)), 6), -999) as multi_loan_in_loan_order_all_createdorderdaysgapmathcount_std
     ,coalesce(max(if((t4.settled_time is null or t4.settled_time>t3.use_create_time) and t3.order_asc_rank>1 and t3.loan_end_date < substr(t3.use_create_time,1,10) and (t3.settled_time is null or substr(t3.settled_time,1,10)> t3.loan_end_date), datediff(cast(t3.loan_end_date as date), cast(t6.create_time as date)),null)), -999) as multi_loan_in_loan_order_all_lastoverdueinstalrisktimegap

from
    (
        select t1.apply_id
             ,t1.cust_no
             ,t1.use_create_time
             ,t2.id
             ,t2.loan_no
             ,t2.settled_time
             ,t2.create_time
             ,t2.loan_end_date
             ,t2.loan_start_date
             ,t2.repaid_principal
             ,t2.repaid_interest
             ,t2.repaid_service_fee
             ,t2.repaid_penalty
             ,dense_rank()over(partition by t1.cust_no,t1.use_create_time order by ala.create_time asc) as order_asc_rank -- 升序排序，1即为最远一笔
          ,dense_rank()over(partition by t1.cust_no,t1.use_create_time order by ala.create_time desc) as order_desc_rank -- 降序排序，1即为最近一笔
          ,last_value(t2.loan_end_date) over (partition by t1.cust_no,t1.use_create_time,t2.loan_no order by t2.loan_end_date ROWS BETWEEN UNBOUNDED PRECEDING AND UNBOUNDED FOLLOWING) as last_loan_end_date -- 该笔订单的整体到期时间
          ,t2.periods
        from target_user as t1
                 left join (
            select *
            from hive_idc.oversea.ods_mx_ast_asset_repay_plan_df
            where pt ='${dt}' -- yyymmdd格式
              and replace(substr(create_time,1,10) ,'-', '') <='${dt}'
              and repay_plan_status != 4
        ) as t2
                           on t1.cust_no = t2.cust_no
                 left join (select * from hive_idc.oversea.ods_mx_ast_asset_loan_info_df where pt ='${dt}') ali ON t2.loan_no = ali.loan_no
                 left join (select * from hive_idc.oversea.ods_mx_ast_asset_loan_apply_df where pt ='${dt}') ala ON ali.loan_apply_no = ala.loan_apply_no
        where t2.create_time < t1.use_create_time
    ) as t3
        left join (select loan_no,loan_apply_no,settled_time,real_loan_amt from hive_idc.oversea.ods_mx_ast_asset_loan_info_df where pt ='${dt}' and loan_status != 4) as t4 on t3.loan_no = t4.loan_no
        left join (select loan_apply_no,seq_no from hive_idc.oversea.ods_mx_ast_asset_loan_apply_df where pt ='${dt}') as t5 on t4.loan_apply_no = t5.loan_apply_no
        left join (select asset_id,create_time,credit_apply_id from hive_idc.oversea.ods_mx_aprv_approve_use_credit_apply_df where pt ='${dt}') as t6 on t5.seq_no = t6.asset_id
        left join (select id,create_time from hive_idc.oversea.ods_mx_aprv_approve_credit_apply_df where pt='${dt}' ) as t7 on t6.credit_apply_id = t7.id
group by t3.apply_id,t3.cust_no,t3.use_create_time) t
-- where use_create_time>'2026-02-02 09:56:00';